import { Component, signal, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { MatSidenavModule } from '@angular/material/sidenav';
import { NavbarComponent } from './navbar/navbar.component';
import { SidebarComponent } from './sidebar/sidebar.component';
import { RouterOutlet, Router, NavigationEnd } from '@angular/router';
import { MatIcon } from '@angular/material/icon';
import { filter } from 'rxjs/operators';

@Component({
  selector: 'app-layout',
  standalone: true,
  imports: [CommonModule, MatSidenavModule, SidebarComponent, NavbarComponent, RouterOutlet, MatIcon],
  templateUrl: './layout.component.html',
  styleUrl: './layout.component.css'
})
export class LayoutComponent {
  private router = inject(Router);

  // signal holding the state 
  isSidebarOpen = signal(false);
  currentUrl = signal('');

  // width setting when open and collapsed by Rahul
  expandedStyle = {
    marginLeft: '230px'
  };
  defaultStyle = {
    marginLeft: '65px'
  };

  constructor() {
    this.currentUrl.set(this.router.url);
    this.router.events.pipe(
      filter(event => event instanceof NavigationEnd)
    ).subscribe((event: any) => {
      this.currentUrl.set(event.url);
    });
  }

  // Toggle functionality for the sidenavbar by Rahul
  toggleSidebar = () => {
    this.isSidebarOpen.set(!this.isSidebarOpen());
  };

  isSpecialRoute(): boolean {
    const url = this.currentUrl();
    return url.includes('pda') || url.includes('fda');
  }
}
